import { defineContract } from 'aether';

export default defineContract({
  name: 'notifications',
  description: 'Handles sending and managing user notifications.',

  dependencies: {
    modules: ['auth'],
  },

  exposes: {
    routes: [
      { method: 'POST', path: '/notifications/send', auth: true }, // Auth required, but with internal role check
    ],
    functions: ['sendNotification'],
    types: ['Notification', 'NotificationError'],
  },

  sideEffects: [
    'writes to: notifications table',
    'dispatches: email/push notifications',
  ],

  invariants: [
    'Notifications must always be associated with a valid user ID.',
    'Only system accounts can send notifications via the API.',
  ],
});
```

