import { AuthError } from 'auth/module.contract'; // Assuming AuthError is exposed

export type Notification = {
  id: string;
  userId: string;
  message: string;
  status: 'pending' | 'sent' | 'failed';
  createdAt: Date;
  sentAt: Date | null;
};

export type NotificationError =
  | { type: 'DatabaseError'; message: string }
  | { type: 'ValidationError'; message: string }
  | { type: 'UnauthorizedError'; message: string }
  | AuthError; // Re-exporting AuthError for convenience
