import { query } from 'lib/db';
import { ok, err, Result } from 'lib/result';
import { Notification, NotificationError } from '../types';

/**
 * Persists notifications in the database and conceptually dispatches them.
 * In a real application, this would trigger an actual email/push service.
 */
export async function sendNotification(
  userIds: string[],
  message: string,
): Promise<Result<true, NotificationError>> {
  if (userIds.length === 0) {
    return err({ type: 'ValidationError', message: 'No user IDs provided.' });
  }
  if (!message.trim()) {
    return err({ type: 'ValidationError', message: 'Notification message cannot be empty.' });
  }

  const now = new Date();
  const values = userIds.map(userId => `('${userId}', '${message}', 'pending', '${now.toISOString()}')`).join(',');

  const insertSql = `
    INSERT INTO notifications (user_id, message, status, created_at)
    VALUES ${values}
    RETURNING id;
  `;

  const dbResult = await query(insertSql);

  if (dbResult.isErr()) {
    console.error('Database error sending notification:', dbResult.error);
    return err({ type: 'DatabaseError', message: 'Failed to persist notifications.' });
  }

  // In a real application, this is where you'd call an external service
  // to send emails or push notifications for each user.
  console.log(`[NOTIFICATION SERVICE] Dispatched notifications to ${userIds.length} users.`);

  return ok(true);
}
