import { requireUser } from 'lib/auth';
import { parseBody } from 'lib/validate';
import { ok, err } from 'lib/result';
import { sendNotification } from '../services/notificationService';
import { NotificationError } from '../types';
import { User } from 'auth/module.contract'; // Import User type from auth module contract
import { z } from 'zod';

// Define the schema for the request body
const SendNotificationSchema = z.object({
  userIds: z.array(z.string().uuid('Invalid user ID format')).min(1, 'At least one user ID is required.'),
  message: z.string().min(1, 'Notification message cannot be empty.'),
});

type SendNotificationBody = z.infer<typeof SendNotificationSchema>;

export default async function sendNotificationRoute(req: Request): Promise<Response> {
  // 1. Authenticate the user and check for 'system' role
  const userResult = await requireUser(req);
  if (userResult.isErr()) {
    // AuthError from requireUser is already a NotificationError type
    return new Response(JSON.stringify({ error: userResult.error.message }), { status: 401, headers: { 'Content-Type': 'application/json' } });
  }

  const user: User = userResult.value;

  // Explicit role check for system service account
  if (user.role !== 'system') {
    const error: NotificationError = { type: 'UnauthorizedError', message: 'Only system accounts can send notifications.' };
    return new Response(JSON.stringify({ error: error.message }), { status: 403, headers: { 'Content-Type': 'application/json' } });
  }

  // 2. Validate the request body
  const bodyResult = await parseBody<SendNotificationBody>(req, SendNotificationSchema);
  if (bodyResult.isErr()) {
    const error: NotificationError = { type: 'ValidationError', message: bodyResult.error.message };
    return new Response(JSON.stringify({ error: error.message }), { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  const { userIds, message } = bodyResult.value;

  // 3. Call the service to send notifications
  const notificationResult = await sendNotification(userIds, message);

  if (notificationResult.isErr()) {
    const error = notificationResult.error;
    let statusCode = 500; // Default to internal server error

    switch (error.type) {
      case 'ValidationError':
        statusCode = 400;
        break;
      case 'DatabaseError':
        statusCode = 500;
        break;
      // AuthError and UnauthorizedError are handled earlier, but included for completeness
      case 'AuthError':
        statusCode = 401;
        break;
      case 'UnauthorizedError':
        statusCode = 403;
        break;
    }
    return new Response(JSON.stringify({ error: error.message }), { status: statusCode, headers: { 'Content-Type': 'application/json' } });
  }

  // 4. Return success response
  return new Response(JSON.stringify({ message: 'Notifications sent successfully.' }), { status: 200, headers: { 'Content-Type': 'application/json' } });
}
